package controllers

import play.api.mvc._
import play.api.libs.json.Json
import slick.jdbc.PostgresProfile.api._

class ProductController(db: Database) extends Controller {

  def searchProducts = Action.async { request =>
    val queryParams = request.queryString
    val whereClauses = queryParams.map {
      case (key, values) => s"$key IN (${values.mkString(", ")})"
    }.mkString(" AND ")

    val sqlFragment = if (whereClauses.nonEmpty) s"WHERE $whereClauses" else ""

    db.run(sql"SELECT * FROM products ${sqlFragment}".as[Product]).map { products =>
      Ok(Json.toJson(products))
    }.recover {
      case e: Exception => InternalServerError(s"Error searching products: ${e.getMessage}")
    }
  }

}

case class Product(id: Int, name: String, price: Double)